func gradeColorClass(grade string) string {
	switch {
	case grade == "A+" || grade == "A":
		return "text-success"
	case grade == "A-" || grade == "B+":
		return "text-success/80"
	case grade == "B" || grade == "B-":
		return "text-info"
	case grade == "C+" || grade == "C":
		return "text-warning"
	case grade == "C-" || grade == "D+" || grade == "D":
		return "text-warning/80"
	default:
		return "text-error"
	}
}

